import { useEffect, useState } from "react";
import axios from "axios";
import { useParams, useNavigate } from "react-router-dom";

export default function DriverRoute() {
  const { id } = useParams();
  const navigate = useNavigate();

  const [task, setTask] = useState(null);

  const START_LAT = 23.2167;
  const START_LNG = 77.4061;

  const getTask = async () => {
    try {
      const res = await axios.get(
        "http://localhost:3000/api/driver/today-task"
      );

      const found = res.data.requests.find(
        (item) => item._id === id
      );

      setTask(found);
    } catch (error) {
      console.log(error);
    }
  };

  useEffect(() => {
    getTask();
  }, []);

  const markArrived = async () => {
    try {
      const res = await axios.put(
        `http://localhost:3000/api/driver/arrived/${id}`
      );

      setTask(res.data.data);
    } catch (error) {
      console.log(error);
    }
  };

  const markCompleted = async () => {
    try {
      const res = await axios.put(
        `http://localhost:3000/api/driver/completed/${id}`
      );

      setTask(res.data.data);

      setTimeout(() => {
        navigate("/driver-dashboard");
      }, 2000);
    } catch (error) {
      console.log(error);
    }
  };

  if (!task) {
    return (
      <div className="min-h-screen flex justify-center items-center text-xl font-bold">
        Loading...
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#4CBB17]/10">

      {/* Route Header */}
      <div className="bg-green-700 text-white py-4">
        <h1 className="text-center text-2xl font-bold">
          🚛 Live Route
        </h1>
      </div>

      {/* Route Info */}
      <div className="bg-white shadow p-4">
        <p className="font-semibold">
          📍 Start : MANIT Bhopal
        </p>

        <p className="mt-2 font-semibold">
          🎯 Destination : {task.location?.location}
        </p>
      </div>

      {/* Map */}
      <div className="w-full h-[350px]">
        <iframe
          title="Map"
          width="100%"
          height="100%"
          className="border-0"
          loading="lazy"
          src={`https://maps.google.com/maps?q=${task.location?.latitude},${task.location?.longitude}&z=14&output=embed`}
        />
      </div>

      {/* Buttons */}
      <div className="flex flex-col items-center mt-8">

        {task.arrivedAt && (
          <div className="bg-yellow-100 p-4 rounded-xl mb-4 w-80 text-center">
            <p className="font-bold">
              Arrived Time
            </p>
            <p>
              {new Date(task.arrivedAt).toLocaleString()}
            </p>
          </div>
        )}

        {task.completedAt && (
          <div className="bg-green-100 p-4 rounded-xl mb-4 w-80 text-center">
            <p className="font-bold">
              Completed Time
            </p>
            <p>
              {new Date(task.completedAt).toLocaleString()}
            </p>
          </div>
        )}

        {task.status === "Scheduled" && (
          <button
            onClick={markArrived}
            className="bg-yellow-500 text-white px-12 py-4 rounded-xl text-xl font-bold"
          >
            Arrived
          </button>
        )}

        {task.status === "Arrived" && (
          <button
            onClick={markCompleted}
            className="bg-green-600 text-white px-12 py-4 rounded-xl text-xl font-bold"
          >
            Completed
          </button>
        )}
      </div>
    </div>
  );
}
